import{_ as t,c as a,o as r,a5 as o}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse(`{"title":"Changelog v3.18.1","description":"NpgsqlRest v3.18.1: Patch release that makes all automatic (server-filled) parameters forward to proxy endpoints consistently, in the endpoint's native…","frontmatter":{"description":"NpgsqlRest v3.18.1: Patch release that makes all automatic (server-filled) parameters forward to proxy endpoints consistently, in the endpoint's native…","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.18.1.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.18.1.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.18.1"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.18.1: Patch release that makes all automatic (server-filled) parameters forward to proxy endpoints consistently, in the endpoint's native…"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.18.1"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.18.1: Patch release that makes all automatic (server-filled) parameters forward to proxy endpoints consistently, in the endpoint's native…"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.18.1.md","filePath":"guide/changelog/v3.18.1.md","lastUpdated":1782480183000}`),s={name:"guide/changelog/v3.18.1.md"};function n(i,e,l,d,h,p){return r(),a("div",null,e[0]||(e[0]=[o('<h1 id="changelog-v3-18-1" tabindex="-1">Changelog v3.18.1 <a class="header-anchor" href="#changelog-v3-18-1" aria-label="Permalink to &quot;Changelog v3.18.1&quot;">​</a></h1><h2 id="version-3-18-1-2026-06-23" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.1" target="_blank" rel="noreferrer">3.18.1</a> (2026-06-23) <a class="header-anchor" href="#version-3-18-1-2026-06-23" aria-label="Permalink to &quot;Version [3.18.1](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.1) (2026-06-23)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.18.0...3.18.1" target="_blank" rel="noreferrer">Full Changelog</a></p><p>Patch release that makes <strong>all automatic (server-filled) parameters forward to proxy endpoints consistently</strong>, in the endpoint&#39;s native parameter shape.</p><h2 id="what-changed" tabindex="-1">What changed <a class="header-anchor" href="#what-changed" aria-label="Permalink to &quot;What changed&quot;">​</a></h2><p>When an endpoint is a proxy, the parameters that NpgsqlRest fills server-side are now forwarded to the upstream <strong>uniformly</strong>, regardless of source:</p><ul><li><strong>user claims</strong> (claim-mapped parameters),</li><li><strong>IP address</strong> parameter,</li><li><strong>HTTP Custom Type</strong> fields (the auto-filled <code>responseBody</code> / <code>responseStatusCode</code> / … on a routine with an HTTP Custom Type parameter),</li><li><strong>resolved-parameter expressions</strong> (values looked up server-side via SQL).</li></ul><p>All of them follow the <strong>same placement rule</strong>, which mirrors how the endpoint itself receives parameters — <strong>not</strong> the HTTP verb:</p><ul><li>The parameter designated as the body parameter (<code>@body_parameter_name</code>) carries the <strong>raw request body</strong>.</li><li>Otherwise placement follows the endpoint&#39;s <strong><code>RequestParamType</code></strong>: <code>QueryString</code> → appended to the proxy <strong>query string</strong>; <code>BodyJson</code> → merged into the proxy <strong>JSON body</strong> (typed: numbers, booleans, embedded JSON, or strings), when the proxy method can carry a JSON body.</li></ul><p>This is <strong>additive</strong>: the verbatim incoming request is still forwarded; the automatic parameters are added on top, so the upstream receives the same parameter set the routine would have.</p><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Previously the behavior was inconsistent: user-claim and IP parameters were always appended to the query string, HTTP Custom Type fields and resolved parameters were not forwarded at all, and a passthrough proxy discarded the auto-filled values entirely (the outbound HTTP Custom Type call fired but its result went nowhere). Now every automatic parameter behaves the same way.</p><h3 id="behavior-change-to-note" tabindex="-1">Behavior change to note <a class="header-anchor" href="#behavior-change-to-note" aria-label="Permalink to &quot;Behavior change to note&quot;">​</a></h3><p>User-claim and IP parameters now follow <code>RequestParamType</code> like every other automatic parameter. For a <code>QueryString</code> endpoint (the default for GET) they remain in the query string, exactly as before. For a <code>BodyJson</code> endpoint they are now merged into the JSON body rather than forced onto the query string. Method does not decide placement — <code>RequestParamType</code> does (a POST endpoint can use <code>param_type query</code> and its parameters then go to the query string).</p><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>Body merging applies only when the forwarded request carries a <strong>JSON</strong> content type; multipart and non-JSON bodies are forwarded verbatim.</li><li>Only the expanded per-field HTTP Custom Type parameters (DB-function shape) are forwarded; single-composite HTTP parameters (SQL-file shape) are not.</li></ul><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><p><code>NpgsqlRestTests/ProxyTests/ProxyHttpTypeProbeTest.cs</code> covers, via a WireMock proxy target that echoes the received URL / body: HTTP-type fields forwarded on the query (GET) and merged into the JSON body (POST, typed); placement following <code>RequestParamType</code> rather than the verb (a <code>param_type query</code> POST forwards to the query, not the body); and a resolved-parameter expression forwarded consistently. Existing user-claim / IP proxy tests continue to pass unchanged (GET → query string). Full suite green (2288).</p>',18)]))}const m=t(s,[["render",n]]);export{g as __pageData,m as default};
